using Favigon.Domain.Entities;
using Favigon.Infrastructure.Context;
using Microsoft.EntityFrameworkCore;

namespace Favigon.Infrastructure.Seeding;

public static class ProjectSeeder
{
  public static async Task SeedAsync(FavigonDbContext context)
  {
    var targetUser = await context.Users.FirstOrDefaultAsync(u => u.Email == "raresmihail2004@gmail.com");
    if (targetUser == null) return;

    await SeedProjectAsync(context, targetUser.Id,
        "Favigon Demo — SaaS Light", "favigon-demo-saas-light", SaasLightDesignJson);
  }

  private static async Task SeedProjectAsync(
      FavigonDbContext context, int userId, string name, string slug, string designJson)
  {
    var existing = await context.Projects
        .FirstOrDefaultAsync(p => p.UserId == userId && p.Slug == slug);

    if (existing != null)
    {
      existing.DesignJson = designJson;
      await context.SaveChangesAsync();
      return;
    }

    context.Projects.Add(new Project
    {
      UserId = userId,
      Name = name,
      Slug = slug,
      IsPublic = true,
      DesignJson = designJson,
    });

    await context.SaveChangesAsync();
  }

